function isNewerVersion(a, b) {
  const pa = String(a).split('.').map(Number), pb = String(b).split('.').map(Number);
  for (let i = 0; i < Math.max(pa.length, pb.length); i++) { const x = pa[i] || 0, y = pb[i] || 0; if (x > y) return true; if (x < y) return false; }
  return false;
}
// Purge le cache applicatif (Service Worker + Cache Storage) puis recharge → récupère les fichiers à jour.
// N'EFFACE PAS localStorage : toutes les données (clients, tournées, réglages, agenda) sont conservées.
async function purgeAndReload() {
  try {
    if ('serviceWorker' in navigator) { const rs = await navigator.serviceWorker.getRegistrations(); await Promise.all(rs.map((x) => x.unregister())); }
    if (window.caches) { const ks = await caches.keys(); await Promise.all(ks.map((k) => caches.delete(k))); }
  } catch { /* ignore */ }
  location.reload();
}
// Récupère le numéro de la dernière release publiée (sans « v »), ou null si indisponible.
async function fetchLatestRelease() {
  if (!UPDATE_REPO) return null;
  const r = await fetch(`https://api.github.com/repos/${UPDATE_REPO}/releases/latest`, { cache: 'no-store' });
  if (!r.ok) return null;
  const j = await r.json();
  return String(j.tag_name || '').replace(/^v/i, '') || null;
}
// Au lancement : vérifie la dernière release GitHub. Si plus récente → purge + recharge (MAJ). Sinon → ouverture normale.
// ---------- Écran de démarrage bloquant : mise à jour + synchro Drive avant utilisation ----------
let _bootSyncFinished = false;
function bootSyncSet(txt) { const el = document.getElementById('bootSyncStatus'); if (el) el.textContent = txt; }
function bootSyncFinish() { if (_bootSyncFinished) return; _bootSyncFinished = true; const el = document.getElementById('bootSync'); if (el) el.classList.add('done'); } // rend la main à l'utilisateur (app pleinement opérationnelle)
async function checkForUpdate() {
  if (!UPDATE_REPO) return;
  try {
    const latest = await fetchLatestRelease();
    if (latest && isNewerVersion(latest, APP_VERSION) && sessionStorage.getItem('ftr.updated') !== latest) {
      sessionStorage.setItem('ftr.updated', latest); // anti-boucle
      bootSyncSet('Nouvelle version v' + latest + ' — mise à jour…'); // l'écran de démarrage reste affiché jusqu'au rechargement
      await purgeAndReload();
    }
  } catch { /* hors-ligne / API indisponible → ouverture normale */ }
}
// Vérification MANUELLE (bouton « Mettre à jour ») avec retour visible. Ignore le garde-fou anti-boucle du lancement.
async function manualCheckForUpdate(statusEl) {
  const set = (cls, txt) => { if (statusEl) { statusEl.className = 'status ' + cls; statusEl.innerHTML = txt; } };
  if (!UPDATE_REPO) { set('err', 'Mise à jour non configurée.'); return; }
  set('', 'Recherche d\'une nouvelle version…');
  let latest;
  try { latest = await fetchLatestRelease(); }
  catch { set('err', 'Impossible de vérifier (hors-ligne ou GitHub indisponible).'); return; }
  if (latest && isNewerVersion(latest, APP_VERSION)) {
    set('ok', `Nouvelle version v${esc(latest)} trouvée — téléchargement et mise à jour…`);
    setTimeout(purgeAndReload, 600);
    return;
  }
  // À jour selon la dernière release publiée → proposer quand même un rechargement forcé (le site peut être en avance sur la release).
  set('ok', `Vous avez déjà la dernière version publiée (v${esc(APP_VERSION)}).<br><button class="btn small" id="forceReload" style="margin-top:6px">Forcer le rechargement</button>`);
  const fr = document.getElementById('forceReload'); if (fr) fr.addEventListener('click', () => { set('', 'Rechargement…'); purgeAndReload(); });
}

// ---------- Persistance ----------
const LS = {
  get(k, d) { try { const v = localStorage.getItem(k); return v == null ? d : JSON.parse(v); } catch { return d; } },
  set(k, v) {
    try { localStorage.setItem(k, JSON.stringify(v)); }
    catch (e) {
      // Quota localStorage dépassé. On libère de la place en jetant UNIQUEMENT les empreintes de synchro (« ftr.syncmeta » →
      // m.hash), qui sont RECONSTRUCTIBLES. Les TOMBSTONES (suppressions, « ftr.tomb ») ne sont PAS reconstructibles : on les
      // met à l'abri AVANT toute purge (y compris ceux d'un ancien format combiné) → aucune fiche supprimée ne peut réapparaître.
      const quota = e && (e.name === 'QuotaExceededError' || e.name === 'NS_ERROR_DOM_QUOTA_REACHED' || e.code === 22 || e.code === 1014);
      if (quota) {
        try {
          let old = {}, durable = {};
          try { old = JSON.parse(localStorage.getItem('ftr.syncmeta') || '{}') || {}; } catch (e0) {}
          try { durable = JSON.parse(localStorage.getItem('ftr.tomb') || '{}') || {}; } catch (e0) {}
          const oldTomb = (old && old.tomb) || {};
          Object.keys(oldTomb).forEach((kind) => { durable[kind] = durable[kind] || {}; const src = oldTomb[kind] || {}; Object.keys(src).forEach((id) => { durable[kind][id] = Math.max(durable[kind][id] || 0, src[id]); }); });
          // ORDRE : alléger d'abord « ftr.syncmeta » (jette les empreintes = libère la place), PUIS écrire les tombstones (les
          // salvés sont déjà en mémoire dans `durable`), enfin réécrire la valeur cible. Les tombstones ne sont jamais perdus.
          localStorage.setItem('ftr.syncmeta', JSON.stringify({ hash: {} })); // on ne jette QUE les empreintes (reconstructibles)
          localStorage.setItem('ftr.tomb', JSON.stringify(durable));          // petit, durable — JAMAIS purgé
          localStorage.setItem(k, JSON.stringify(v));
          try { rebuildSyncHashes(); } catch (e3) {} // #1 : reconstruit les empreintes depuis l'état courant SANS bumper updatedAt → le prochain syncStamp ne rebumpe pas TOUT (sinon la version locale gagnerait le LWW et écraserait des éditions distantes)
          return;
        } catch (e2) { /* toujours plein après purge → on laisse remonter l'erreur (pas d'écrasement silencieux) */ }
      }
      throw e;
    }
  },
};
const uid = () => 'id' + Date.now().toString(36) + Math.random().toString(36).slice(2, 10); // robustesse : ~8 caractères aléatoires (36^8) au lieu de 1e6 → plus de collision d'id en création groupée (import/réinjection créant clients+chevaux dans le même tick)

