  const r = btn.getBoundingClientRect();
  pop.style.position = 'fixed'; pop.style.right = 'auto'; pop.style.bottom = 'auto'; pop.style.top = '0'; pop.style.left = '0';
  if (w.classList.contains('gp-date')) pop.style.width = '';
