// natif (format YYYY-MM-DD) + dispatch input/change → handlers intacts. Libellé affiché JJ/MM/AAAA en gris.
const GP_MONTHS = ['janvier', 'février', 'mars', 'avril', 'mai', 'juin', 'juillet', 'août', 'septembre', 'octobre', 'novembre', 'décembre'];
