  const inp = w._gpInp, pop = w.querySelector('.gp-sel-pop'), sel = gpDateParse(inp.value), now = new Date();
  if (!w._gpYM) { const b = sel || { y: now.getFullYear(), mo: now.getMonth() + 1 }; w._gpYM = { y: b.y, m: b.mo }; }
  const y = w._gpYM.y, m = w._gpYM.m;
