const PROV_BASE_LABEL = { tva: 'TVA', vehicule: 'Véhicule', materiel: 'Matériel', social: 'Social', ipp: 'IPP', isoc: 'ISoc', precompte: 'Précompte', manuel: 'Manuel' };
