  $('plGuideC2').addEventListener('change', (e) => { S.planche.gridGuide.color2 = e.target.value || '#2b7bd6'; saveSettings(); });
  if ($('plFormatSel')) $('plFormatSel').addEventListener('change', (e) => { S.planche.format = e.target.value || 'r43'; saveSettings(); });
